using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> succeeded — Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? resolvedInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({resolvedInfo!.Type.Name})");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> → not available");
}

// Now demonstrate a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo<UnknownType>(out JsonTypeInfo<UnknownType>? missing))
{
    Console.WriteLine($"TryGetTypeInfo<UnknownType> → found ({missing!.Type.Name})");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType> → not available (no exception thrown)");
}

// Types
public record Person(string Name, int Age);
public record UnknownType(string Value);

// A minimal source-gen context that only resolves Person
[JsonSourceGenerationOptions]
[JsonSerializable(typeof(Person))]
public partial class LimitedContext : JsonSerializerContext;

